class Solution {
public:
    int findBottomLeftValue(TreeNode* root) {
        queue<TreeNode*> q;
        q.push(root);
        int left = root->val;
        while (!q.empty()) {
            left = q.front()->val;
            int sz = q.size();
            while (sz--) {
                auto* n = q.front(); q.pop();
                if (n->left) q.push(n->left);
                if (n->right) q.push(n->right);
            }
        }
        return left;
    }
};
